        position: relative;
        height: 7px;
        background: #173238;
        border: 1px solid #315b60;
        overflow: hidden;
      }
      .bar i {
        position: absolute;
        inset: 0 auto 0 0;
        width: 0%;
        background: linear-gradient(90deg, #b8f7eb, #8bd8ff);
      }
      .controls {
        display: grid;
        gap: 6px;
      }
      label {
        display: grid;
        grid-template-columns: 62px 1fr 34px;
        align-items: center;
        gap: 6px;
        color: #b8dfe3;
      }
      input[type="range"] {
        width: 100%;
        accent-color: #9ee7e5;
      }
      .value {
        color: #e8fbff;
        text-align: right;
        font-variant-numeric: tabular-nums;
      }
    </style>
    <div class="cooling">
      <div class="top">
        <h1>cooling music</h1>
        <button id="toggle" type="button" aria-pressed="${state.enabled}" title="play">${state.enabled ? "on" : "off"}</button>
      </div>
      <div class="pond" aria-hidden="true">
        <div class="horizon"></div>
        <div class="ripple" id="rippleA" style="--x:32%;--y:47%;--s:58px"></div>
        <div class="ripple" id="rippleB" style="--x:68%;--y:61%;--s:76px"></div>
        <div class="ripple" id="rippleC" style="--x:50%;--y:39%;--s:46px"></div>
      </div>
      <div class="controls">
        <div class="meters">
          <div class="meter"><span>air</span><span class="bar"><i id="airBar"></i></span></div>
          <div class="meter"><span>ice</span><span class="bar"><i id="iceBar"></i></span></div>
          <div class="meter"><span>drop</span><span class="bar"><i id="dropBar"></i></span></div>
          <div class="meter"><span>pad</span><span class="bar"><i id="padBar"></i></span></div>
        </div>
        <label>cool <input id="coolness" type="range" min="0" max="1" step="0.001" value="${state.coolness}"><span class="value" id="coolnessValue"></span></label>
        <label>breeze <input id="breeze" type="range" min="0" max="1" step="0.001" value="${state.breeze}"><span class="value" id="breezeValue"></span></label>
        <label>chimes <input id="chimes" type="range" min="0" max="1" step="0.001" value="${state.chimes}"><span class="value" id="chimesValue"></span></label>
        <label>drops <input id="droplets" type="range" min="0" max="1" step="0.001" value="${state.droplets}"><span class="value" id="dropletsValue"></span></label>
      </div>
    </div>
  `;

  const toggle = ctx.domRoot.querySelector("#toggle");
  const sliders = {
    coolness: ctx.domRoot.querySelector("#coolness"),
    breeze: ctx.domRoot.querySelector("#breeze"),
    chimes: ctx.domRoot.querySelector("#chimes"),
    droplets: ctx.domRoot.querySelector("#droplets")
  };
  const valueLabels = {
    coolness: ctx.domRoot.querySelector("#coolnessValue"),
    breeze: ctx.domRoot.querySelector("#breezeValue"),
    chimes: ctx.domRoot.querySelector("#chimesValue"),
    droplets: ctx.domRoot.querySelector("#dropletsValue")
  };
  const bars = {
    air: ctx.domRoot.querySelector("#airBar"),
    ice: ctx.domRoot.querySelector("#iceBar"),
    drop: ctx.domRoot.querySelector("#dropBar"),
    pad: ctx.domRoot.querySelector("#padBar")
  };
  const ripples = [
    ctx.domRoot.querySelector("#rippleA"),
    ctx.domRoot.querySelector("#rippleB"),
    ctx.domRoot.querySelector("#rippleC")
  ];

  const output = ctx.audioCtx.createGain();
  const highpass = ctx.audioCtx.createBiquadFilter();
  const dry = ctx.audioCtx.createGain();
  const delaySend = ctx.audioCtx.createGain();
  const delay = ctx.audioCtx.createDelay(1.6);
  const delayFeedback = ctx.audioCtx.createGain();
  const delayFilter = ctx.audioCtx.createBiquadFilter();
  const convolver = ctx.audioCtx.createConvolver();
  const reverbGain = ctx.audioCtx.createGain();
  const analyser = ctx.audioCtx.createAnalyser();

  output.gain.value = state.enabled ? 0.55 : 0.0001;
  highpass.type = "highpass";
  highpass.frequency.value = 95;
  dry.gain.value = 0.78;
  delay.delayTime.value = 0.44;
  delayFeedback.gain.value = 0.34;
  delayFilter.type = "lowpass";
  delayFilter.frequency.value = 3600;
  reverbGain.gain.value = 0.34;
  analyser.fftSize = 128;

  highpass.connect(dry);
  dry.connect(output);
  delaySend.connect(delay);
  delay.connect(delayFilter);
  delayFilter.connect(delayFeedback);
  delayFeedback.connect(delay);
  delayFilter.connect(output);
  convolver.connect(reverbGain);
  reverbGain.connect(output);
  output.connect(analyser);
  analyser.connect(ctx.audioOut);

  const makeImpulse = () => {
    const sampleRate = ctx.audioCtx.sampleRate;
    const length = Math.floor(sampleRate * 2.4);
    const impulse = ctx.audioCtx.createBuffer(2, length, sampleRate);
    for (let channel = 0; channel < 2; channel += 1) {
      const data = impulse.getChannelData(channel);
      for (let i = 0; i < length; i += 1) {
        const decay = Math.pow(1 - i / length, 3.2);
        data[i] = (Math.random() * 2 - 1) * decay * 0.42;
      }
    }
    return impulse;
  };
  convolver.buffer = makeImpulse();

  const noiseBuffer = ctx.audioCtx.createBuffer(2, ctx.audioCtx.sampleRate * 3, ctx.audioCtx.sampleRate);
  for (let channel = 0; channel < noiseBuffer.numberOfChannels; channel += 1) {
    const data = noiseBuffer.getChannelData(channel);
    let held = 0;
    for (let i = 0; i < data.length; i += 1) {
      if (i % 360 === 0) held = Math.random() * 2 - 1;
      data[i] = held * 0.35 + (Math.random() * 2 - 1) * 0.08;
    }
  }

  const breezeSource = ctx.audioCtx.createBufferSource();
  const breezeGain = ctx.audioCtx.createGain();
  const breezeHigh = ctx.audioCtx.createBiquadFilter();
  const breezeLow = ctx.audioCtx.createBiquadFilter();
  breezeSource.buffer = noiseBuffer;
  breezeSource.loop = true;
  breezeHigh.type = "highpass";
  breezeHigh.frequency.value = 720;
  breezeLow.type = "lowpass";
  breezeLow.frequency.value = 2800;
  breezeGain.gain.value = state.enabled ? state.breeze * 0.048 : 0.0001;
  breezeSource.connect(breezeHigh);
  breezeHigh.connect(breezeLow);
  breezeLow.connect(breezeGain);
  breezeGain.connect(output);
  breezeSource.start();

  const activeNodes = new Set();
  const timeouts = new Set();
  const remember = (...nodes) => nodes.forEach((node) => activeNodes.add(node));
  const disconnectLater = (time, ...nodes) => {
    const timeout = setTimeout(() => {
      nodes.forEach((node) => {
        try { node.disconnect(); } catch (_) {}
        activeNodes.delete(node);
      });
      timeouts.delete(timeout);
    }, Math.max(80, (time - now()) * 1000 + 120));
    timeouts.add(timeout);
  };

  const bellRatios = [1, 2.003, 2.996, 4.113];
  const triggerChime = (midi, velocity, time, duration, step) => {
    const t = Math.max(time, now() + 0.004);
    const freq = midiToFreq(midi);
    const color = clamp(state.coolness, 0, 1);
    const stopAt = t + duration * (5.4 + color * 4.6);
    const voice = ctx.audioCtx.createGain();
    const amp = ctx.audioCtx.createGain();
    const filter = ctx.audioCtx.createBiquadFilter();
    const pan = ctx.audioCtx.createStereoPanner();

    voice.gain.value = 0.72;
    filter.type = "bandpass";
    filter.frequency.setValueAtTime(freq * (1.9 + color * 0.7), t);
    filter.Q.setValueAtTime(1.8 + color * 4.2, t);
    pan.pan.setValueAtTime((randomFor(step, 41) - 0.5) * 0.9, t);
    amp.gain.setValueAtTime(0.0001, t);
    amp.gain.exponentialRampToValueAtTime(0.08 * velocity * (0.55 + state.chimes), t + 0.016);
    amp.gain.exponentialRampToValueAtTime(0.0001, stopAt);

    voice.connect(filter);
    filter.connect(amp);
    amp.connect(pan);
    pan.connect(highpass);
    pan.connect(delaySend);
    pan.connect(convolver);

    const oscillators = bellRatios.map((ratio, index) => {
      const osc = ctx.audioCtx.createOscillator();
      const partialGain = ctx.audioCtx.createGain();
      osc.type = index === 0 ? "sine" : "triangle";
      osc.frequency.setValueAtTime(freq * ratio, t);
      osc.detune.setValueAtTime((randomFor(step, index + 5) - 0.5) * 5, t);
      partialGain.gain.setValueAtTime([1, 0.42, 0.2, 0.12][index], t);
      osc.connect(partialGain);
      partialGain.connect(voice);
      osc.start(t);
      osc.stop(stopAt + 0.08);
      remember(osc, partialGain);
      return [osc, partialGain];
    }).flat();

    remember(voice, amp, filter, pan, ...oscillators);
    disconnectLater(stopAt + 0.12, voice, amp, filter, pan, ...oscillators);
    pulse.ice = Math.max(pulse.ice, velocity);
  };

  const triggerDrop = (time, step) => {
    const t = Math.max(time, now() + 0.004);
    const stopAt = t + 0.32;
    const osc = ctx.audioCtx.createOscillator();
    const noise = ctx.audioCtx.createBufferSource();
    const amp = ctx.audioCtx.createGain();
    const noiseAmp = ctx.audioCtx.createGain();
    const filter = ctx.audioCtx.createBiquadFilter();
    const pan = ctx.audioCtx.createStereoPanner();
    const freq = 980 + randomFor(step, 13) * 980 + state.coolness * 460;

    osc.type = "sine";
    osc.frequency.setValueAtTime(freq * 1.35, t);
    osc.frequency.exponentialRampToValueAtTime(freq, t + 0.095);
    noise.buffer = noiseBuffer;
    filter.type = "bandpass";
    filter.frequency.setValueAtTime(freq * 1.7, t);
    filter.Q.setValueAtTime(8, t);
    pan.pan.setValueAtTime((randomFor(step, 17) - 0.5) * 0.7, t);
    amp.gain.setValueAtTime(0.0001, t);
    amp.gain.exponentialRampToValueAtTime(0.05 * state.droplets, t + 0.006);
    amp.gain.exponentialRampToValueAtTime(0.0001, stopAt);
    noiseAmp.gain.setValueAtTime(0.026 * state.droplets, t);
    noiseAmp.gain.exponentialRampToValueAtTime(0.0001, t + 0.07);

    osc.connect(amp);
    noise.connect(filter);
    filter.connect(noiseAmp);
    amp.connect(pan);
    noiseAmp.connect(pan);
    pan.connect(highpass);
    pan.connect(convolver);
    osc.start(t);
    noise.start(t);
    osc.stop(stopAt + 0.05);
    noise.stop(t + 0.08);

    remember(osc, noise, amp, noiseAmp, filter, pan);
    disconnectLater(stopAt + 0.08, osc, noise, amp, noiseAmp, filter, pan);
    pulse.drop = Math.max(pulse.drop, 0.9);

    const ripple = ripples[step % ripples.length];
    ripple.classList.remove("live");
    ripple.offsetWidth;
    ripple.style.setProperty("--x", `${24 + randomFor(step, 31) * 52}%`);
    ripple.style.setProperty("--y", `${34 + randomFor(step, 37) * 35}%`);
    ripple.style.setProperty("--s", `${46 + randomFor(step, 43) * 42}px`);
    ripple.classList.add("live");
  };

  const chordVoices = [
    [0, 7, 14, 21],
    [-3, 4, 12, 19],
    [-5, 2, 9, 16],
    [-7, 0, 7, 14]
  ];
  const triggerPad = (time, duration, chordIndex) => {
    const t = Math.max(time, now() + 0.004);
    const stopAt = t + duration * 18;
    const voice = ctx.audioCtx.createGain();
    const filter = ctx.audioCtx.createBiquadFilter();
    const pan = ctx.audioCtx.createStereoPanner();
    const amp = ctx.audioCtx.createGain();
    filter.type = "lowpass";
    filter.frequency.setValueAtTime(760 + state.coolness * 1250, t);
    filter.Q.setValueAtTime(0.6, t);
    pan.pan.setValueAtTime(chordIndex % 2 ? -0.18 : 0.18, t);
    amp.gain.setValueAtTime(0.0001, t);
    amp.gain.linearRampToValueAtTime(0.065 * (0.6 + state.coolness * 0.4), t + duration * 3.4);
    amp.gain.setTargetAtTime(0.0001, t + duration * 13, duration * 2.6);
    voice.connect(filter);
    filter.connect(amp);
    amp.connect(pan);
    pan.connect(highpass);
    pan.connect(convolver);

    const oscillators = chordVoices[chordIndex % chordVoices.length].map((offset, index) => {
      const osc = ctx.audioCtx.createOscillator();
      const gain = ctx.audioCtx.createGain();
      osc.type = index % 2 ? "sine" : "triangle";
      osc.frequency.setValueAtTime(midiToFreq(state.rootMidi - 24 + offset), t);
      osc.detune.setValueAtTime((index - 1.5) * (3 + state.coolness * 5), t);
      gain.gain.setValueAtTime(index === 0 ? 0.55 : 0.36, t);
      osc.connect(gain);
      gain.connect(voice);
      osc.start(t);
      osc.stop(stopAt + duration);
      remember(osc, gain);
      return [osc, gain];
    }).flat();

    remember(voice, filter, pan, amp, ...oscillators);
    disconnectLater(stopAt + duration, voice, filter, pan, amp, ...oscillators);
    pulse.pad = Math.max(pulse.pad, 0.75);
  };

  const scale = [0, 2, 4, 7, 9, 12, 14, 16, 19, 21, 24];
  const chimePattern = [0, null, 7, null, 4, null, 9, null, 12, null, 7, null, 16, null, 14, null];
  const pulse = { air: state.breeze, ice: 0, drop: 0, pad: 0 };
  let lastBpm = 92;
  let phase = 0;

  const applyContinuous = (time = now()) => {
    setTarget(output.gain, state.enabled ? 0.55 : 0.0001, time, 0.08);
    setTarget(breezeGain.gain, state.enabled ? state.breeze * 0.048 : 0.0001, time, 0.08);
    setTarget(breezeLow.frequency, 1800 + state.coolness * 3600, time, 0.12);
    setTarget(delayFeedback.gain, 0.24 + state.coolness * 0.22, time, 0.08);
    setTarget(delayFilter.frequency, 2200 + state.coolness * 3600, time, 0.08);
    setTarget(reverbGain.gain, 0.22 + state.coolness * 0.22, time, 0.08);
  };

  const unsubscribeClock = ctx.clock.onTick(({ step, time, duration, bpm }) => {
    lastBpm = bpm || lastBpm;
    const t = Math.max(time, now() + 0.004);
    applyContinuous(t);
    delay.delayTime.setTargetAtTime((60 / lastBpm) * 0.75, t, 0.04);
    if (!state.enabled) return;

    const current = ((step % 16) + 16) % 16;
    if (current === 0) {
      triggerPad(t, duration, Math.floor(step / 16));
    }

    const chimeOffset = chimePattern[current];
    if (chimeOffset !== null && randomFor(step, 3) < state.chimes) {
      const octaveLift = randomFor(step, 4) > 0.68 ? 12 : 0;
      triggerChime(state.rootMidi + chimeOffset + octaveLift, 0.54 + randomFor(step, 6) * 0.36, t, duration, step);
    }

    const shouldDrop = randomFor(step, 21) < state.droplets * (current % 2 ? 0.5 : 0.24);
    if (shouldDrop) {
      triggerDrop(t + duration * (0.15 + randomFor(step, 22) * 0.62), step);
    }

    if (current === 11 && state.chimes > 0.52) {
      const note = scale[Math.floor(randomFor(step, 61) * scale.length)];
      triggerChime(state.rootMidi + 12 + note, 0.28, t + duration * 0.5, duration * 0.7, step + 5000);
    }
  });

  const onToggle = () => {
    state.enabled = !state.enabled;
    toggle.setAttribute("aria-pressed", String(state.enabled));
    toggle.textContent = state.enabled ? "on" : "off";
    applyContinuous();
  };
  toggle.addEventListener("click", onToggle);

  const onSlider = (key) => {
    state[key] = Number(sliders[key].value);
    applyContinuous();
    renderValues();
  };
  const sliderHandlers = Object.fromEntries(
    Object.keys(sliders).map((key) => {
      const handler = () => onSlider(key);
      sliders[key].addEventListener("input", handler);
      return [key, handler];
    })
  );

  const renderValues = () => {
    for (const key of Object.keys(valueLabels)) {
      valueLabels[key].textContent = Math.round(state[key] * 100);
    }
  };
  renderValues();
  applyContinuous();

  let raf = 0;
  const freqData = new Uint8Array(analyser.frequencyBinCount);
  const animate = () => {
    raf = requestAnimationFrame(animate);
    analyser.getByteFrequencyData(freqData);
    let airEnergy = 0;
    for (let i = 14; i < 32; i += 1) airEnergy += freqData[i] || 0;
    phase += 0.012 + state.breeze * 0.012;
    pulse.air = clamp(state.breeze * 0.45 + airEnergy / 4800 + Math.sin(phase) * 0.08, 0, 1);
    pulse.ice *= 0.92;
    pulse.drop *= 0.88;
    pulse.pad *= 0.965;
    bars.air.style.width = `${clamp(pulse.air, 0, 1) * 100}%`;
    bars.ice.style.width = `${clamp(pulse.ice, 0, 1) * 100}%`;
    bars.drop.style.width = `${clamp(pulse.drop, 0, 1) * 100}%`;
    bars.pad.style.width = `${clamp(pulse.pad, 0, 1) * 100}%`;
  };
  animate();

  return {
    update() {},
    getState() {
      return { ...state };
    },
    destroy() {
      cancelAnimationFrame(raf);
      unsubscribeClock();
      toggle.removeEventListener("click", onToggle);
      for (const [key, handler] of Object.entries(sliderHandlers)) {
        sliders[key].removeEventListener("input", handler);
      }
      timeouts.forEach((timeout) => clearTimeout(timeout));
      timeouts.clear();
      try { breezeSource.stop(); } catch (_) {}
      activeNodes.forEach((node) => {
        try { node.stop(); } catch (_) {}
        try { node.disconnect(); } catch (_) {}
      });
      activeNodes.clear();
      [
        breezeSource, breezeGain, breezeHigh, breezeLow, output, highpass, dry,
        delaySend, delay, delayFeedback, delayFilter, convolver, reverbGain, analyser
      ].forEach((node) => {
        try { node.disconnect(); } catch (_) {}
      });
    }
  };
}
